--
-- Estrutura para tabela `users`
--

CREATE TABLE `users` (
  `id` bigint(20) UNSIGNED NOT NULL,
  `referrer_id` bigint(20) UNSIGNED DEFAULT NULL,
  `referral_code` varchar(20) DEFAULT NULL,
  `commission_percentage` decimal(5,2) NOT NULL DEFAULT 1.00,
  `commission_fixed` decimal(10,2) NOT NULL DEFAULT 0.00,
  `name` varchar(255) NOT NULL,
  `fantasy_name` varchar(255) DEFAULT NULL,
  `email` varchar(255) NOT NULL,
  `photo` varchar(255) DEFAULT NULL,
  `whatsapp` varchar(20) DEFAULT NULL,
  `document` varchar(20) DEFAULT NULL,
  `cep` varchar(10) DEFAULT NULL,
  `address` varchar(255) DEFAULT NULL,
  `city` varchar(100) DEFAULT NULL,
  `state` varchar(2) DEFAULT NULL,
  `business_type` varchar(100) DEFAULT NULL,
  `business_sector` varchar(100) DEFAULT NULL,
  `birth_date` date DEFAULT NULL,
  `terms_accepted` tinyint(1) NOT NULL DEFAULT 0,
  `role` enum('user','admin','gerente') NOT NULL DEFAULT 'user',
  `assigned_gateway_id` bigint(20) UNSIGNED DEFAULT NULL,
  `withdrawal_type` enum('manual','automatic') NOT NULL DEFAULT 'manual',
  `assigned_baas_id` bigint(20) UNSIGNED DEFAULT NULL,
  `retry_gateway_id` bigint(20) UNSIGNED DEFAULT NULL,
  `retry_enabled` tinyint(1) NOT NULL DEFAULT 0,
  `withdrawal_fee_fixed` decimal(10,2) NOT NULL DEFAULT 0.00,
  `withdrawal_fee_percentage` decimal(5,2) NOT NULL DEFAULT 0.00,
  `withdrawal_fee_type` enum('global','fixed','percentage','both') NOT NULL DEFAULT 'global',
  `retention_cycle` int(11) DEFAULT NULL,
  `retention_quantity` int(11) DEFAULT NULL,
  `retention_enabled` tinyint(1) NOT NULL DEFAULT 1,
  `is_blocked` tinyint(1) NOT NULL DEFAULT 0,
  `blocked_at` timestamp NULL DEFAULT NULL,
  `blocked_reason` text DEFAULT NULL,
  `api_secret` varchar(64) DEFAULT NULL,
  `api_public_key` varchar(255) DEFAULT NULL,
  `api_public_key_created_at` timestamp NULL DEFAULT NULL,
  `api_secret_created_at` timestamp NULL DEFAULT NULL,
  `api_secret_last_used_at` timestamp NULL DEFAULT NULL,
  `api_token` text DEFAULT NULL,
  `account_type` enum('pessoa_fisica','pessoa_juridica') NOT NULL DEFAULT 'pessoa_fisica',
  `email_verified_at` timestamp NULL DEFAULT NULL,
  `password` varchar(255) NOT NULL,
  `remember_token` varchar(100) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

