--
-- Estrutura para tabela `user_fees`
--

CREATE TABLE `user_fees` (
  `id` bigint(20) UNSIGNED NOT NULL,
  `user_id` bigint(20) UNSIGNED NOT NULL,
  `payment_method` enum('pix','credit_card','bank_slip') NOT NULL,
  `percentage_fee` decimal(5,2) NOT NULL DEFAULT 0.00,
  `fixed_fee` decimal(8,2) NOT NULL DEFAULT 0.00,
  `min_amount` decimal(10,2) NOT NULL DEFAULT 0.01,
  `max_amount` decimal(12,2) DEFAULT NULL,
  `min_transaction_value` decimal(10,2) DEFAULT NULL,
  `max_transaction_value` decimal(10,2) DEFAULT NULL,
  `is_active` tinyint(1) NOT NULL DEFAULT 1,
  `metadata` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`metadata`)),
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

